/**
 * Nxcode SDK Type Definitions
 */
export interface NxcodeUser {
    id: string;
    email: string;
    name: string | null;
    avatar: string | null;
    balance: number;
}
export interface NxcodeConfig {
    appId: string;
    name: string;
    billingMode: 'creator_pays' | 'user_pays';
    apiEndpoint: string;
    firstLoginBonus?: number;
}
export interface AuthResult {
    success: boolean;
    token?: string;
    refreshToken?: string;
    expiresAt?: string;
    user?: NxcodeUser;
    error?: string;
}
export interface ChargeOptions {
    amount: number;
    description: string;
    metadata?: Record<string, unknown>;
}
export interface ChargeResult {
    success: boolean;
    transactionId?: string;
    amount?: number;
    creatorShare?: number;
    newBalance?: number;
    error?: string;
}
export interface Transaction {
    id: string;
    appId: string;
    amount: number;
    description: string;
    status: string;
    createdAt: string;
}
export type AuthStateCallback = (user: NxcodeUser | null) => void;
